     1→import './login.css';
     2→import React, {useEffect, useState} from "react";
     3→import { useNavigate, Link } from "react-router-dom";
     4→import { useAuth } from '../../Context/useAuth.js';
     5→import supabase from '../../utils/supabaseClient.js';
     6→const LoginPage = () =>{
     7→    const [showPass, setShowPass] = useState(false)
     8→    const [password, setPassword] = useState(null)
     9→    const [email, setEmail] = useState(null);
    10→    const [errorMessage, setErrorMessage] = useState('')
    11→
    12→    const {session} = useAuth();
    13→    
    14→    const navigate = useNavigate(null);
    15→    const handleShowPass = (e) =>{
    16→        e.stopPropagation();
    17→        setShowPass(!showPass)
    18→    }
    19→    const handleNavigate = (e) =>{
    20→        e.stopPropagation();
    21→        return navigate('/signUp');
    22→    }
    23→    const handleLogin = async(e) =>{
    24→        e.stopPropagation();
    25→        try {
    26→            const {error} = await supabase.auth.signInWithPassword({email: email, password: password})
    27→            if(error){
    28→                return setErrorMessage(error.message)
    29→            }
    30→            navigate('/home')
    31→        } catch (error) {
    32→            console.error('Error during sign-up:', error.message);
    33→            setErrorMessage(error.message);
    34→        } finally {
    35→            setEmail(null);
    36→            setPassword(null);
    37→        }
    38→    }
    39→
    40→    useEffect(() =>{
    41→        if(session){
    42→            navigate('/home')
    43→        }
    44→    }, [session])
    45→    return(
    46→        <>
    47→        <div className='log-in-bg-container'>
    48→            <img className='log-in-bg-img' src="/assets/log-in-page-bg.png" alt="" />
    49→        </div>
    50→        <div className='log-in-page-bg-container'>
    51→
    52→            <div className='login-page-container'>
    53→                <div className='input-container'>
    54→                    <div className='input-container-child'>
    55→                        <input value={email ? email : ''} onChange={(e) => setEmail(e.target.value)} className='login-input' type="text" placeholder='email'/>
    56→                    </div>
    57→                    <div className='input-container-child'>
    58→                        <input value={password ? password : ''} onChange={(e) => setPassword(e.target.value)} className='login-input' type={showPass ? 'text' : 'password'} placeholder='password'/>
    59→                        {password && (
    60→                            <div onClick={(e) => handleShowPass(e)} className='show-bttn'>
    61→                                {showPass ? 'hide' : 'show'}
    62→                            </div>
    63→                        )}
    64→                    
    65→                    </div>
    66→                
    67→                    <button onClick={(e) => handleLogin(e)} disabled={!password} className={!password ? 'log-in-bttn-disabled' : 'log-in-bttn'}>
    68→                        Log in
    69→                    </button>
    70→                </div>
    71→
    72→                <div className='switch-container'>
    73→                    Don't have an account? <span onClick={(e) => handleNavigate(e)} className='sign-up-bttn'>Sign up</span>
    74→                </div>
    75→
    76→                {errorMessage && (
    77→                    <div className='error-message'>
    78→                        {errorMessage}
    79→                    </div>  
    80→                )}
    81→            </div>
    82→
    83→            <div className='login-logo'>
    84→                Iskrib
    85→            </div>
    86→        </div>
    87→        
    88→        </>
    89→    )
    90→}
    91→export default LoginPage

