     2→import React, {useEffect, useState} from "react";
     3→import { useNavigate, Link } from "react-router-dom";
     4→import supabase from '../../utils/supabaseClient';
     5→import Turnstile from 'react-turnstile'
     6→import { MoonLoader } from "react-spinners";
     7→import { useAuth } from '../../Context/useAuth';
     8→
     9→const SITE_KEY = import.meta.env.VITE_SITE_KEY;
    10→
    11→const SignUp = () => {
    12→    const {session, isLoading} = useAuth();
    13→
    14→    const [password, setPassword] = useState(null);
    15→    const [email, setEmail] = useState(null);
    16→    const [showPass, setShowPass] = useState(false)
    17→    const [errorMessage, setErrorMessage] = useState(null);
    18→    const [isLoadingSignUp, setIsLoadingSignUp] = useState(false)
    19→    const navigate = useNavigate(null);
    20→
    21→    const [captchaToken, setCaptchaToken] = useState(null);
    22→
    23→    const handleShowPass = (e) =>{
    24→        e.stopPropagation();
    25→        setShowPass(!showPass)
    26→    }
    27→
    28→    // //wait the turnstile script to be ready
    29→    // useEffect(() =>{
    30→    //     const interval = setInterval(() => {
    31→    //         if(window.turnstile){
    32→    //             clearInterval(interval);
    33→    //             window.turnstile.render('#captcha-container', {
    34→    //                 sitekey: SITE_KEY,
    35→    //                 callback: (token) =>setCaptchaToken(token),
    36→    //                 'error-callback': () => setCaptchaToken(null),
    37→    //                 'expired-callback': () => setCaptchaToken(null),
    38→    //             })
    39→    //         }
    40→    //     }, 300);
    41→    // }, [])
    42→
    43→
    44→    const handleSignUp = async(e) =>{
    45→        e.stopPropagation()
    46→        setIsLoadingSignUp(true)
    47→        const validateEmail = (email) =>{
    48→            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    49→            return emailRegex.test(email)
    50→        }
    51→        if(!validateEmail(email)){
    52→            setIsLoadingSignUp(false)
    53→           return setErrorMessage('Email is not valid')
    54→        }
    55→        if (!captchaToken) {
    56→            setIsLoadingSignUp(false)
    57→            return setErrorMessage("Please complete the CAPTCHA first.");
    58→        }
    59→
    60→        try {
    61→            const res = await fetch(`${import.meta.env.VITE_BACKEND_URL}/verify-turnstile`, {
    62→                method: 'POST',
