     1→import { createContext, useContext, useState, useEffect } from 'react';
     2→import supabase from '../utils/supabaseClient';
     3→import { useQuery, useQueryClient } from '@tanstack/react-query';
     4→import { getNotificationsCount, getUserData } from '../../API/Api';
     5→
     6→
     7→export const AuthContext = createContext();
     8→
     9→export const AuthProvider = ({children}) => {
    10→    const [loading, setLoading] = useState(true);
    11→
    12→    const queryClient = useQueryClient();
    13→
    14→    const {data: authData, isLoading: isAuthLoading} = useQuery({
    15→        queryKey: ['authsession'],
    16→        queryFn: async() =>{
    17→            const {data, error} = await supabase.auth.getSession();
    18→            if(error) throw error;
    19→            return data.session
    20→        },
    21→        staleTime: 1000 * 60 * 60,
    22→        cacheTime: 1000 * 60 * 60,
    23→    })
    24→
    25→    // console.log(authData)
    26→
    27→    useEffect(() =>{
    28→        let mounted = true;
    29→        // (async () =>{
    30→        //     const {data} = await supabase.auth.getSession();
    31→        //     if(mounted){
    32→        //         queryClient.setQueryData(['authsession'], data?.session)
    33→        //         setLoading(false)
    34→        //     }
    35→        // })();
    36→
    37→        //listen for login or logout events
    38→        if(!isAuthLoading && mounted){
    39→            setLoading(false)
    40→        }
    41→        const {data: listener} = supabase.auth.onAuthStateChange((_event, session) => {
    42→            if(mounted){
    43→                queryClient.setQueryData(['authsession'], session ?? null);
    44→                setLoading(false)
    45→            } 
    46→        })
    47→        return() => listener.subscription.unsubscribe();
    48→        
    49→    }, [isAuthLoading])
    50→
    51→    const {data: userData, isLoading} = useQuery({
    52→            queryKey: ['userData', authData?.user?.id],
    53→            queryFn: ({queryKey}) => getUserData(queryKey[1]),
    54→            enabled: !!authData?.access_token, //only runs if token exists
    55→            staleTime: 1000 * 60 * 60,
    56→            cacheTime: 1000 * 60 * 60,
    57→        })
    58→
    59→    const {data: notifCount, isLoading: isLoadingNotifCount} = useQuery({
    60→        queryKey: ['notifcounts', authData?.user?.id],
    61→        queryFn: ({queryKey}) => getNotificationsCount(queryKey[1]),
    62→        enabled: !!authData?.access_token,
    63→        staleTime: 1000 * 60 * 60,
    64→        cacheTime: 1000 * 60 * 60,
    65→    })
    66→    
    67→    //hook for realtime notifications
    68→    useEffect(() =>{
    69→        if(!userData) return;
    70→
    71→        const channel = supabase
    72→        .channel('notifications')
    73→        .on('postgres_changes',
    74→        {event: 'INSERT', schema: 'public', table: 'notifications', filter: `receiver_id=eq.${userData?.userData?.[0]?.id}`},
    75→        (payload) => {
    76→            console.log('new notification:', payload)
    77→            queryClient.setQueryData(['notifcounts', authData?.user?.id], (old) => ({count: (old?.count ? old?.count : 0) + 1}));
    78→        }
    79→    )
    80→    .subscribe();
    81→
    82→    return () => {
    83→        supabase.removeChannel(channel);
    84→    }
    85→
    86→    },[userData])
    87→    
    88→
    89→    // useEffect(() => {
    90→    //     console.log(userData?.userData?.[0].id);
    91→    // }, [userData])
    92→
    93→    const signOut = async() =>{
    94→        await supabase.auth.signOut();
    95→        queryClient.setQueryData(['authsession'], null)
    96→        queryClient.clear();
    97→
    98→    }
    99→
   100→    const value = {
   101→        session: authData,
   102→        user: userData,
   103→        loading: loading,
   104→        isLoading: isLoading,
   105→        notifCount: notifCount?.count,
   106→        signOut
   107→    }
   108→    return <AuthContext.Provider value={value}>
   109→        {children}
   110→    </AuthContext.Provider>
   111→}

